-- ============================================================
-- STAGING: Planilla produccion (hoja 'Pedido corte') - ULTIMAS 800 ordenes
-- Volcado fiel para migrar a ProdOrdenes/ProdOrdenesDetalle (Paso 2).
-- Tabla desechable de staging. La corre Israel. NO es data de negocio final.
-- EsTE=1 marca la variante 'talle especial' (discontinuada) para descartarla en el Paso 2.
-- ============================================================
SET NOCOUNT ON;
IF OBJECT_ID('dbo.ProdPlanillaCorteStg','U') IS NOT NULL DROP TABLE dbo.ProdPlanillaCorteStg;
CREATE TABLE dbo.ProdPlanillaCorteStg (
    Id INT IDENTITY(1,1) PRIMARY KEY,
    NroOrden INT NULL,
    Temporada NVARCHAR(40) NULL,
    Anio INT NULL,
    Proveedor NVARCHAR(10) NULL,
    Codigo NVARCHAR(50) NULL,
    Descripcion NVARCHAR(300) NULL,
    DescripcionEcom NVARCHAR(300) NULL,
    Muestra BIT NULL,
    CurvaTalles NVARCHAR(100) NULL,
    Talles NVARCHAR(100) NULL,
    PaletaColores NVARCHAR(80) NULL,
    Colores NVARCHAR(200) NULL,
    TipoArticulo NVARCHAR(40) NULL,
    Categoria NVARCHAR(40) NULL,
    Linea NVARCHAR(40) NULL,
    Material NVARCHAR(50) NULL,
    Familia NVARCHAR(50) NULL,
    Subfamilia NVARCHAR(80) NULL,
    Marca NVARCHAR(50) NULL,
    TelaNuestra BIT NULL,
    CantRollosEntregados DECIMAL(18,2) NULL,
    PesoRollosKg DECIMAL(18,2) NULL,
    LongitudRollosMts DECIMAL(18,2) NULL,
    PrecioProveedor DECIMAL(18,2) NULL,
    FechaOrden DATE NULL,
    CantPrendasEstimadas DECIMAL(18,2) NULL,
    FechaEntregaTela DATE NULL,
    FechaPedidoEtiqueta DATE NULL,
    FechaEnvioEtiquetas DATE NULL,
    FechaEstEntregaProv DATE NULL,
    FechaEntrega DATE NULL,
    CantEtiquetasEnviadas DECIMAL(18,2) NULL,
    PrendasEtiquetadas DECIMAL(18,2) NULL,
    CantPrendasRecibidas DECIMAL(18,2) NULL,
    Costo DECIMAL(18,2) NULL,
    Combo NVARCHAR(40) NULL,
    ArticuloNuevo BIT NULL,
    DestinoArmado NVARCHAR(40) NULL,
    LinkFoto NVARCHAR(300) NULL,
    DescProveedor NVARCHAR(150) NULL,
    Estado NVARCHAR(60) NULL,
    EstimadasRecibidas DECIMAL(18,2) NULL,
    MesActivacion NVARCHAR(40) NULL,
    CalidadAprobado BIT NULL,
    CalidadDesaprobado BIT NULL,
    EsTE BIT NOT NULL DEFAULT(0)
);










-- Control
SELECT total=COUNT(*), ordenes=COUNT(DISTINCT NroOrden), te=SUM(CAST(EsTE AS int)) FROM dbo.ProdPlanillaCorteStg;